command.text:
&CommandCheckTaxCodeBeforeSave;
if not exists(select 1 from @@table where ma_dvcs = $ma_dvcs.OldValue) begin select 'ma_dvcs' as field, replace(@$recordHasBeenChanged, '%s', rtrim($ma_dvcs.OldValue)) as message return end
if @ma_dvcs <> $ma_dvcs.OldValue begin if exists(select 1 from @@table where ma_dvcs = @ma_dvcs) begin select 'ma_dvcs' as field, replace(@$exists, '%s', rtrim(@ma_dvcs)) as message return end end

script.text:
      &ScriptCheckTaxCode;
      /* <flatten type="Javascript"> */
function setObjectFormHidden(f, c) {
  for (var i = 0; i < c.length; i++) {
    var o = i < 3 ? f.getItem(c[i]) : $get(c[i]);
    $common.setVisible(o.parentNode.parentNode.parentNode, false);
  }
}
/* </flatten> */
